initScript:
const managerBase = new URL('.', location.href).pathname.replace(/\/$/, '');
const apiBase = managerBase + '/api/file';
const baseDir = '/.temp';
const namedTestFile = 'api-test-named.txt';
return {
  apiBase, baseDir, namedTestFile,
  createFileUrl: apiBase + '/create_file.php',
  scanFileUrl: apiBase + '/scan_file.php',
  writeFileUrl: apiBase + '/write_file.php',
  readFileUrl: apiBase + '/read_file.php',
  renameFileUrl: apiBase + '/rename_file.php',
  deleteFileUrl: apiBase + '/delete_file.php',
  message: 'init done'
};

tests.scriptText:
const text1 = await utils.postForm(createFileUrl, { dir: baseDir });
const m1 = text1.match(/\[(.+?)\]/);
assert(m1 && m1[1], 'create(default): parse fail');
const text2 = await utils.postForm(createFileUrl, { dir: baseDir, name: namedTestFile });
const m2 = text2.match(/\[(.+?)\]/);
assert(m2 && m2[1], 'create(named): parse fail');
return { defaultPath: m1[1], namedPath: m2[1], message: 'created 2 files' };

const text = await utils.postForm(scanFileUrl, { path: baseDir });
const arr = JSON.parse(text || '[]');
assert(Array.isArray(arr), 'scan: result not array');
assert(arr.includes(utils.basename(defaultPath)), 'scan: default missing');
assert(arr.includes(utils.basename(namedPath)), 'scan: named missing');
return { message: 'scan ok' };

await utils.postForm(writeFileUrl, { path: namedPath, content: 'hello test' });
const text = await utils.postForm(readFileUrl, { path: namedPath });
assert(text.includes('hello test'), 'write: verify read mismatch');
return { message: 'written + verified=' + namedPath };

const text = await utils.postForm(readFileUrl, { path: namedPath });
assert(text.includes('hello test'), 'read: content mismatch');
return { message: 'read ok' };

const text = await utils.postForm(renameFileUrl, { path: namedPath, name: 'api-test-renamed.txt' });
const m = text.match(/to \[(.+?)\]/);
assert(m && m[1], 'rename: parse fail');
const arr = JSON.parse((await utils.postForm(scanFileUrl, { path: baseDir })) || '[]');
assert(Array.isArray(arr), 'rename: scan result not array');
assert(!arr.includes(utils.basename(namedPath)), 'rename: old name still exists');
assert(arr.includes(utils.basename(m[1])), 'rename: new name missing');
return { renamedPath: m[1], message: 'renamed + verified=' + m[1] };

await utils.postForm(deleteFileUrl, { path: defaultPath });
await utils.postForm(deleteFileUrl, { path: renamedPath });
const arr = JSON.parse((await utils.postForm(scanFileUrl, { path: baseDir })) || '[]');
assert(Array.isArray(arr), 'delete: scan result not array');
assert(!arr.includes(utils.basename(defaultPath)), 'delete: default still exists');
assert(!arr.includes(utils.basename(renamedPath)), 'delete: renamed still exists');
return { message: 'deleted + verified' };
